```c++
#include <iostream>
#include <fstream>
#include <string>
#include <vector>

using namespace std;

int main() {
    string filename;
    string word;
    int count = 0;

    cout << "Enter the name of the text file: ";
    cin >> filename;

    cout << "Enter the word to search for: ";
    cin >> word;

    ifstream infile(filename);
    if (!infile) {
        cout << "Error: Could not open file " << filename << endl;
        return 1;
    }

    vector<string> lines;
    string line;

    while (getline(infile, line)) {
        lines.push_back(line);
    }

    infile.close();

    for (int i = 0; i < lines.size(); i++) {
        int count = 0;
        size_t pos = 0;

        while ((pos = lines[i].find(word, pos)) != string::npos) {
            count++;
            pos += word.length();
        }

        int new_count = count;

        if (new_count == 0) {
            new_count = 1;
        }

        cout << "Line " << i+1 << ": " << new_count << endl;
    }

    return 0;
}
```

Here's how the program works:

1. The user is prompted to enter the name of the text file and the word to search for.
2. The program opens the file and reads it line by line into a vector of strings.
3. The program loops through each line in the vector, searching for the specified word using the `find()` function.
4. The number of times the word appears in the line is counted, and the total count for the line is calculated.
5. The program outputs the line number and the total count for each line that contains the specified word.

Note that this program assumes that the text file contains only one word to search for per line. If the text file contains multiple words per line, the program will only count the first occurrence of the specified word on each line.

